const raw = $input.first().json;
const stdout = raw.stdout || '';
const stderr = raw.stderr || '';
const exitCode = raw.code;

if (exitCode !== 0 || stderr) {
  throw new Error(`Login failed: exit=${exitCode}, stderr=${stderr}`);
}

try {
  const response = JSON.parse(stdout);
  if (!response.token) {
    throw new Error(`No token in response: ${stdout}`);
  }
  return [{
    json: {
      token: response.token,
      expires_in: response.expires_in || 3600,
      timestamp: new Date().toISOString()
    }
  }];
} catch (e) {
  throw new Error(`Parse error: ${e.message}. Raw: ${stdout.substring(0, 200)}`);
}

const raw = $input.first().json;
const stdout = raw.stdout || '';
const exitCode = raw.code;

if (exitCode !== 0) {
  throw new Error(`Transactions request failed: exit=${exitCode}, stderr=${raw.stderr}`);
}

let apiResponse;
try {
  apiResponse = JSON.parse(stdout);
} catch (e) {
  throw new Error(`JSON parse error: ${e.message}. Raw: ${stdout.substring(0, 300)}`);
}

const transactions = Array.isArray(apiResponse) ? apiResponse : (apiResponse.transactions || apiResponse.data || []);
if (!Array.isArray(transactions)) {
  throw new Error(`Expected array, got: ${typeof transactions}`);
}

return transactions.map(t => {
  const cp = t.counterparty || {};
  const details = t.details || {};
  const thisAccount = t.this_account || {};
  const cpRouting = cp.account_routing || {};
  return {
    json: {
      bind_id: t.id,
      tipo: details.type || 'TRANSFERENCIAS_RECIBIDAS',
      estado: details.completed ? 'COMPLETED' : 'IN_PROGRESS',
      monto: Math.abs(parseFloat(details.value?.amount || 0)),
      moneda: details.value?.currency || 'ARS',
      descripcion: details.description || null,
      concepto: details.motive || null,
      origen_nombre: cp.name || null,
      origen_cbu: cpRouting.address || null,
      origen_cuit: cp.id || null,
      destino_cuenta: thisAccount.id || null,
      fecha_inicio: details.posted || null,
      fecha_fin: details.completed || null,
      fecha_negocio: details.posted ? details.posted.split('T')[0] : null,
      datos_raw: JSON.stringify(t)
    }
  };
});

const items = $input.all();
return [{
  json: {
    tipo_sync: 'TRANSFERENCIAS',
    estado: 'OK',
    registros: items.length,
    nuevos: items.length,
    actualizados: 0,
    errores: 0,
    detalle_error: null,
    fecha_desde: new Date(Date.now() - 1*24*60*60*1000).toISOString(),
    fecha_hasta: new Date().toISOString(),
    duracion_ms: 0
  }
}];

const data = $input.first().json;
if (data.errores > 0 || data.estado === 'ERROR') {
  return [{ json: data }];
}
return [];

